package com.example.home_chores_automation_app.data.repository

import android.content.Context
import android.content.SharedPreferences
import com.example.home_chores_automation_app.data.model.AppNotification
import com.example.home_chores_automation_app.data.model.Group
import com.example.home_chores_automation_app.data.model.Task
import com.example.home_chores_automation_app.data.model.User
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken

class AppRepository private constructor(context: Context) {

    private val prefs: SharedPreferences =
        context.getSharedPreferences("home_chores_data", Context.MODE_PRIVATE)
    private val gson = Gson()

    companion object {
        @Volatile
        private var INSTANCE: AppRepository? = null

        fun getInstance(context: Context): AppRepository =
            INSTANCE ?: synchronized(this) {
                INSTANCE ?: AppRepository(context.applicationContext).also { INSTANCE = it }
            }
    }

    private val userListType = object : TypeToken<MutableList<User>>() {}.type

    private fun getString(key: String): String? = prefs.getString(key, null)
    private fun putString(key: String, value: String) = prefs.edit().putString(key, value).apply()

    // ── USERS ────────────────────────────────────────────────────────────────

    private fun loadUsers(): MutableList<User> {
        val json = getString("users") ?: return mutableListOf()
        return gson.fromJson(json, userListType)
    }

    private fun saveUsers(list: MutableList<User>) = putString("users", gson.toJson(list))

    fun createUser(user: User) {
        val list = loadUsers()
        list.add(user)
        saveUsers(list)
    }

    fun findUserByEmail(email: String): User? =
        loadUsers().find { it.email.equals(email, ignoreCase = true) }

    fun findUserById(id: String): User? =
        loadUsers().find { it.id == id }

    fun getAllUsers(): List<User> = loadUsers()

    fun updateUser(user: User) {
        val list = loadUsers()
        val idx = list.indexOfFirst { it.id == user.id }
        if (idx >= 0) { list[idx] = user; saveUsers(list) }
    }

    // ── GROUPS ───────────────────────────────────────────────────────────────

    private val groupListType = object : TypeToken<MutableList<Group>>() {}.type

    private fun loadGroups(): MutableList<Group> {
        val json = getString("groups") ?: return mutableListOf()
        return gson.fromJson(json, groupListType)
    }

    private fun saveGroups(list: MutableList<Group>) = putString("groups", gson.toJson(list))

    fun createGroup(group: Group) {
        val list = loadGroups()
        list.add(group)
        saveGroups(list)
    }

    fun getGroupsForUser(userId: String): List<Group> =
        loadGroups().filter { it.adminId == userId || it.memberIds.contains(userId) }

    fun findGroupById(id: String): Group? =
        loadGroups().find { it.id == id }

    fun findGroupByInviteCode(code: String): Group? =
        loadGroups().find { it.inviteCode.equals(code, ignoreCase = true) }

    fun updateGroup(group: Group) {
        val list = loadGroups()
        val idx = list.indexOfFirst { it.id == group.id }
        if (idx >= 0) { list[idx] = group; saveGroups(list) }
    }

    fun deleteGroup(groupId: String) {
        val list = loadGroups()
        list.removeAll { it.id == groupId }
        saveGroups(list)
    }

    // ── TASKS ────────────────────────────────────────────────────────────────

    private val taskListType = object : TypeToken<MutableList<Task>>() {}.type

    private fun loadTasks(): MutableList<Task> {
        val json = getString("tasks") ?: return mutableListOf()
        return gson.fromJson(json, taskListType)
    }

    private fun saveTasks(list: MutableList<Task>) = putString("tasks", gson.toJson(list))

    fun createTask(task: Task) {
        val list = loadTasks()
        list.add(task)
        saveTasks(list)
    }

    fun getTasksForGroup(groupId: String): List<Task> =
        loadTasks().filter { it.groupId == groupId }

    fun updateTask(task: Task) {
        val list = loadTasks()
        val idx = list.indexOfFirst { it.id == task.id }
        if (idx >= 0) { list[idx] = task; saveTasks(list) }
    }

    fun deleteTask(taskId: String) {
        val list = loadTasks()
        list.removeAll { it.id == taskId }
        saveTasks(list)
    }

    fun deleteTasksForGroup(groupId: String) {
        val list = loadTasks()
        list.removeAll { it.groupId == groupId }
        saveTasks(list)
    }

    // ── NOTIFICATIONS ────────────────────────────────────────────────────────

    private val notifListType = object : TypeToken<MutableList<AppNotification>>() {}.type

    private fun loadNotifications(): MutableList<AppNotification> {
        val json = getString("notifications") ?: return mutableListOf()
        return gson.fromJson(json, notifListType)
    }

    private fun saveNotifications(list: MutableList<AppNotification>) =
        putString("notifications", gson.toJson(list))

    fun addNotification(notification: AppNotification) {
        val list = loadNotifications()
        list.add(0, notification)
        saveNotifications(list)
    }

    fun getNotificationsForUser(userId: String): List<AppNotification> =
        loadNotifications().filter { it.userId == userId }

    fun markAllRead(userId: String) {
        val list = loadNotifications()
        val updated = list.map { if (it.userId == userId) it.copy(isRead = true) else it }.toMutableList()
        saveNotifications(updated)
    }

    fun getUnreadCount(userId: String): Int =
        loadNotifications().count { it.userId == userId && !it.isRead }
}

package com.example.home_chores_automation_app.data.repository

import android.content.Context
import android.content.SharedPreferences
import com.example.home_chores_automation_app.data.model.AppNotification
import com.example.home_chores_automation_app.data.model.Group
import com.example.home_chores_automation_app.data.model.Task
import com.example.home_chores_automation_app.data.model.User
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken

class AppRepository private constructor(context: Context) {

    private val prefs: SharedPreferences =
        context.getSharedPreferences("home_chores_data", Context.MODE_PRIVATE)
    private val gson = Gson()

    companion object {
        @Volatile
        private var INSTANCE: AppRepository? = null

        fun getInstance(context: Context): AppRepository =
            INSTANCE ?: synchronized(this) {
                INSTANCE ?: AppRepository(context.applicationContext).also { INSTANCE = it }
            }
    }

    private val userListType = object : TypeToken<MutableList<User>>() {}.type

    private fun getString(key: String): String? = prefs.getString(key, null)
    private fun putString(key: String, value: String) = prefs.edit().putString(key, value).apply()

    // ── USERS ────────────────────────────────────────────────────────────────

    private fun loadUsers(): MutableList<User> {
        val json = getString("users") ?: return mutableListOf()
        return gson.fromJson(json, userListType)
    }

    private fun saveUsers(list: MutableList<User>) = putString("users", gson.toJson(list))

    fun createUser(user: User) {
        val list = loadUsers()
        list.add(user)
        saveUsers(list)
    }

    fun findUserByEmail(email: String): User? =
        loadUsers().find { it.email.equals(email, ignoreCase = true) }

    fun findUserById(id: String): User? =
        loadUsers().find { it.id == id }

    fun getAllUsers(): List<User> = loadUsers()

    fun updateUser(user: User) {
        val list = loadUsers()
        val idx = list.indexOfFirst { it.id == user.id }
        if (idx >= 0) { list[idx] = user; saveUsers(list) }
    }

    fun updateUserProfile(user: User) {
        updateUser(user)
    }

    fun updateUserPassword(userId: String, newPassword: String) {
        val list = loadUsers()
        val idx = list.indexOfFirst { it.id == userId }
        if (idx >= 0) {
            val updatedUser = list[idx].copy(password = newPassword)
            list[idx] = updatedUser
            saveUsers(list)
        }
    }

    fun updateProfilePicture(userId: String, base64Image: String?) {
        val list = loadUsers()
        val idx = list.indexOfFirst { it.id == userId }
        if (idx >= 0) {
            val updatedUser = list[idx].copy(profilePictureBase64 = base64Image)
            list[idx] = updatedUser
            saveUsers(list)
        }
    }

    fun checkEmailExists(email: String, excludeUserId: String): Boolean {
        return loadUsers().any { it.email.equals(email, ignoreCase = true) && it.id != excludeUserId }
    }

    // ── GROUPS ───────────────────────────────────────────────────────────────

    private val groupListType = object : TypeToken<MutableList<Group>>() {}.type

    private fun loadGroups(): MutableList<Group> {
        val json = getString("groups") ?: return mutableListOf()
        return gson.fromJson(json, groupListType)
    }

    private fun saveGroups(list: MutableList<Group>) = putString("groups", gson.toJson(list))

    fun createGroup(group: Group) {
        val list = loadGroups()
        list.add(group)
        saveGroups(list)
    }

    fun getGroupsForUser(userId: String): List<Group> =
        loadGroups().filter { it.adminId == userId || it.memberIds.contains(userId) }

    fun findGroupById(id: String): Group? =
        loadGroups().find { it.id == id }

    fun findGroupByInviteCode(code: String): Group? =
        loadGroups().find { it.inviteCode.equals(code, ignoreCase = true) }

    fun updateGroup(group: Group) {
        val list = loadGroups()
        val idx = list.indexOfFirst { it.id == group.id }
        if (idx >= 0) { list[idx] = group; saveGroups(list) }
    }

    fun deleteGroup(groupId: String) {
        val list = loadGroups()
        list.removeAll { it.id == groupId }
        saveGroups(list)
    }

    // ── TASKS ────────────────────────────────────────────────────────────────

    private val taskListType = object : TypeToken<MutableList<Task>>() {}.type

    private fun loadTasks(): MutableList<Task> {
        val json = getString("tasks") ?: return mutableListOf()
        return gson.fromJson(json, taskListType)
    }

    private fun saveTasks(list: MutableList<Task>) = putString("tasks", gson.toJson(list))

    fun createTask(task: Task) {
        val list = loadTasks()
        list.add(task)
        saveTasks(list)
    }

    fun getTasksForGroup(groupId: String): List<Task> =
        loadTasks().filter { it.groupId == groupId }

    fun updateTask(task: Task) {
        val list = loadTasks()
        val idx = list.indexOfFirst { it.id == task.id }
        if (idx >= 0) { list[idx] = task; saveTasks(list) }
    }

    fun deleteTask(taskId: String) {
        val list = loadTasks()
        list.removeAll { it.id == taskId }
        saveTasks(list)
    }

    fun deleteTasksForGroup(groupId: String) {
        val list = loadTasks()
        list.removeAll { it.groupId == groupId }
        saveTasks(list)
    }

    // ── NOTIFICATIONS ────────────────────────────────────────────────────────

    private val notifListType = object : TypeToken<MutableList<AppNotification>>() {}.type

    private fun loadNotifications(): MutableList<AppNotification> {
        val json = getString("notifications") ?: return mutableListOf()
        return gson.fromJson(json, notifListType)
    }

    private fun saveNotifications(list: MutableList<AppNotification>) =
        putString("notifications", gson.toJson(list))

    fun addNotification(notification: AppNotification) {
        val list = loadNotifications()
        list.add(0, notification)
        saveNotifications(list)
    }

    fun getNotificationsForUser(userId: String): List<AppNotification> =
        loadNotifications().filter { it.userId == userId }

    fun markAllRead(userId: String) {
        val list = loadNotifications()
        val updated = list.map { if (it.userId == userId) it.copy(isRead = true) else it }.toMutableList()
        saveNotifications(updated)
    }

    fun getUnreadCount(userId: String): Int =
        loadNotifications().count { it.userId == userId && !it.isRead }
}

package com.example.home_chores_automation_app.home

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.core.widget.addTextChangedListener
import androidx.fragment.app.Fragment
import androidx.navigation.fragment.findNavController
import com.example.home_chores_automation_app.R
import com.example.home_chores_automation_app.data.prefs.SessionManager
import com.example.home_chores_automation_app.data.repository.AppRepository
import com.example.home_chores_automation_app.databinding.FragmentChangePasswordBinding

class ChangePasswordFragment : Fragment() {

    private var _binding: FragmentChangePasswordBinding? = null
    private val binding get() = _binding!!

    private lateinit var session: SessionManager
    private lateinit var repo: AppRepository
    private lateinit var currentUser: com.example.home_chores_automation_app.data.model.User

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentChangePasswordBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        session = SessionManager(requireContext())
        repo = AppRepository.getInstance(requireContext())

        val userId = session.getCurrentUserId() ?: return
        currentUser = repo.findUserById(userId) ?: return

        // Validation listeners
        binding.etOldPassword.addTextChangedListener {
            validateOldPassword()
            updateChangeButton()
        }

        binding.etNewPassword.addTextChangedListener {
            validateNewPassword()
            validateConfirmPassword()
            updateChangeButton()
        }

        binding.etConfirmPassword.addTextChangedListener {
            validateConfirmPassword()
            updateChangeButton()
        }

        binding.btnChangePassword.setOnClickListener {
            if (validateForm()) {
                changePassword()
            }
        }

        binding.btnCancel.setOnClickListener {
            findNavController().popBackStack()
        }

        binding.btnBack.setOnClickListener {
            findNavController().popBackStack()
        }

        // Initial validation
        validateForm()
    }

    private fun validateOldPassword(): Boolean {
        val oldPassword = binding.etOldPassword.text.toString()
        return if (oldPassword.isEmpty()) {
            binding.tilOldPassword.error = "Old password is required"
            false
        } else if (oldPassword != currentUser.password) {
            binding.tilOldPassword.error = "Old password is incorrect"
            false
        } else {
            binding.tilOldPassword.error = null
            true
        }
    }

    private fun validateNewPassword(): Boolean {
        val newPassword = binding.etNewPassword.text.toString()
        return if (newPassword.length < 6) {
            binding.tilNewPassword.error = "Password must be at least 6 characters"
            false
        } else {
            binding.tilNewPassword.error = null
            true
        }
    }

    private fun validateConfirmPassword(): Boolean {
        val newPassword = binding.etNewPassword.text.toString()
        val confirmPassword = binding.etConfirmPassword.text.toString()
        return if (confirmPassword.isEmpty()) {
            binding.tilConfirmPassword.error = "Confirm password is required"
            false
        } else if (newPassword != confirmPassword) {
            binding.tilConfirmPassword.error = "Passwords do not match"
            false
        } else {
            binding.tilConfirmPassword.error = null
            true
        }
    }

    private fun validateForm(): Boolean {
        val oldValid = validateOldPassword()
        val newValid = validateNewPassword()
        val confirmValid = validateConfirmPassword()
        return oldValid && newValid && confirmValid
    }

    private fun updateChangeButton() {
        binding.btnChangePassword.isEnabled = validateForm()
    }

    private fun changePassword() {
        binding.btnChangePassword.isEnabled = false
        binding.btnChangePassword.text = "Changing..."

        val newPassword = binding.etNewPassword.text.toString()

        repo.updateUserPassword(currentUser.id, newPassword)

        Toast.makeText(requireContext(), "Password changed successfully", Toast.LENGTH_SHORT).show()

        findNavController().popBackStack()
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.home_chores_automation_app.home

import android.os.Bundle
import android.util.Patterns
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.core.widget.addTextChangedListener
import androidx.fragment.app.Fragment
import androidx.navigation.fragment.findNavController
import com.example.home_chores_automation_app.R
import com.example.home_chores_automation_app.data.prefs.SessionManager
import com.example.home_chores_automation_app.data.repository.AppRepository
import com.example.home_chores_automation_app.databinding.FragmentEditProfileBinding
import com.google.android.material.textfield.TextInputLayout

class EditProfileFragment : Fragment() {

    private var _binding: FragmentEditProfileBinding? = null
    private val binding get() = _binding!!

    private lateinit var session: SessionManager
    private lateinit var repo: AppRepository
    private lateinit var currentUser: com.example.home_chores_automation_app.data.model.User

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentEditProfileBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        session = SessionManager(requireContext())
        repo = AppRepository.getInstance(requireContext())

        val userId = session.getCurrentUserId() ?: return
        currentUser = repo.findUserById(userId) ?: return

        // Pre-fill fields
        binding.etName.setText(currentUser.name)
        binding.etEmail.setText(currentUser.email)

        // Validation listeners
        binding.etName.addTextChangedListener {
            validateName()
            updateSaveButton()
        }

        binding.etEmail.addTextChangedListener {
            validateEmail()
            updateSaveButton()
        }

        binding.btnSave.setOnClickListener {
            if (validateForm()) {
                saveProfile()
            }
        }

        binding.btnCancel.setOnClickListener {
            findNavController().popBackStack()
        }

        binding.btnBack.setOnClickListener {
            findNavController().popBackStack()
        }

        // Initial validation
        validateForm()
    }

    private fun validateName(): Boolean {
        val name = binding.etName.text.toString().trim()
        return if (name.isEmpty()) {
            binding.tilName.error = "Name is required"
            false
        } else {
            binding.tilName.error = null
            true
        }
    }

    private fun validateEmail(): Boolean {
        val email = binding.etEmail.text.toString().trim()
        return when {
            email.isEmpty() -> {
                binding.tilEmail.error = "Email is required"
                false
            }
            !Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                binding.tilEmail.error = "Invalid email format"
                false
            }
            repo.checkEmailExists(email, currentUser.id) -> {
                binding.tilEmail.error = "Email already exists"
                false
            }
            else -> {
                binding.tilEmail.error = null
                true
            }
        }
    }

    private fun validateForm(): Boolean {
        val nameValid = validateName()
        val emailValid = validateEmail()
        return nameValid && emailValid
    }

    private fun updateSaveButton() {
        binding.btnSave.isEnabled = validateForm()
    }

    private fun saveProfile() {
        binding.btnSave.isEnabled = false
        binding.btnSave.text = "Saving..."

        val updatedUser = currentUser.copy(
            name = binding.etName.text.toString().trim(),
            email = binding.etEmail.text.toString().trim()
        )

        repo.updateUserProfile(updatedUser)

        Toast.makeText(requireContext(), "Profile updated successfully", Toast.LENGTH_SHORT).show()

        findNavController().popBackStack()
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.home_chores_automation_app.home

import android.content.Intent
import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.navigation.fragment.findNavController
import com.example.home_chores_automation_app.auth.AuthActivity
import com.example.home_chores_automation_app.data.prefs.SessionManager
import com.example.home_chores_automation_app.data.repository.AppRepository
import com.example.home_chores_automation_app.databinding.FragmentProfileBinding
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class ProfileFragment : Fragment() {

    private var _binding: FragmentProfileBinding? = null
    private val binding get() = _binding!!

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentProfileBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        val session = SessionManager(requireContext())
        val repo = AppRepository.getInstance(requireContext())
        val userId = session.getCurrentUserId() ?: return
        val user = repo.findUserById(userId) ?: return

        // Avatar initial
        binding.tvAvatarInitial.text = user.name.first().uppercaseChar().toString()

        // Info rows
        binding.tvName.text = user.name
        binding.tvEmail.text = user.email

        val dateFormat = SimpleDateFormat("dd MMM yyyy", Locale.getDefault())
        binding.tvMemberSince.text = dateFormat.format(Date(user.createdAt))

        // Stats
        val groups = repo.getGroupsForUser(userId)
        binding.tvGroupCount.text = groups.size.toString()

        val allTasks = groups.flatMap { repo.getTasksForGroup(it.id) }
        val assignedTasks = allTasks.filter { it.assignedTo == userId }
        binding.tvTaskCount.text = assignedTasks.size.toString()
        binding.tvCompletedCount.text = assignedTasks.count { it.isCompleted }.toString()

        binding.btnBack.setOnClickListener {
            findNavController().popBackStack()
        }

        binding.btnLogout.setOnClickListener {
            session.logout()
            startActivity(Intent(requireContext(), AuthActivity::class.java).apply {
                flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
            })
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.home_chores_automation_app.home

import android.app.Activity
import android.content.Intent
import android.graphics.Bitmap
import android.graphics.BitmapFactory
import android.net.Uri
import android.os.Bundle
import android.util.Base64
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.fragment.app.Fragment
import androidx.navigation.fragment.findNavController
import com.example.home_chores_automation_app.R
import com.example.home_chores_automation_app.auth.AuthActivity
import com.example.home_chores_automation_app.data.prefs.SessionManager
import com.example.home_chores_automation_app.data.repository.AppRepository
import com.example.home_chores_automation_app.databinding.FragmentProfileBinding
import java.io.ByteArrayOutputStream
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class ProfileFragment : Fragment() {

    private var _binding: FragmentProfileBinding? = null
    private val binding get() = _binding!!

    private lateinit var session: SessionManager
    private lateinit var repo: AppRepository
    private lateinit var currentUser: com.example.home_chores_automation_app.data.model.User

    private val galleryLauncher = registerForActivityResult(ActivityResultContracts.GetContent()) { uri: Uri? ->
        uri?.let { handleImageSelection(it) }
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentProfileBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        session = SessionManager(requireContext())
        repo = AppRepository.getInstance(requireContext())
        val userId = session.getCurrentUserId() ?: return
        currentUser = repo.findUserById(userId) ?: return

        setupAvatar()
        setupInfo()
        setupStats()
        setupButtons()
    }

    private fun setupAvatar() {
        binding.tvAvatarInitial.text = currentUser.name.first().uppercaseChar().toString()

        if (currentUser.profilePictureBase64 != null) {
            try {
                val decodedBytes = Base64.decode(currentUser.profilePictureBase64, Base64.DEFAULT)
                val bitmap = BitmapFactory.decodeByteArray(decodedBytes, 0, decodedBytes.size)
                binding.ivProfilePicture.setImageBitmap(bitmap)
                binding.ivProfilePicture.visibility = View.VISIBLE
                binding.tvAvatarInitial.visibility = View.GONE
            } catch (e: Exception) {
                // Fallback to initial
                binding.ivProfilePicture.visibility = View.GONE
                binding.tvAvatarInitial.visibility = View.VISIBLE
            }
        } else {
            binding.ivProfilePicture.visibility = View.GONE
            binding.tvAvatarInitial.visibility = View.VISIBLE
        }
    }

    private fun setupInfo() {
        binding.tvName.text = currentUser.name
        binding.tvEmail.text = currentUser.email

        val dateFormat = SimpleDateFormat("dd MMM yyyy", Locale.getDefault())
        binding.tvMemberSince.text = dateFormat.format(Date(currentUser.createdAt))
    }

    private fun setupStats() {
        val groups = repo.getGroupsForUser(currentUser.id)
        binding.tvGroupCount.text = groups.size.toString()

        val allTasks = groups.flatMap { repo.getTasksForGroup(it.id) }
        val assignedTasks = allTasks.filter { it.assignedTo == currentUser.id }
        binding.tvTaskCount.text = assignedTasks.size.toString()
        binding.tvCompletedCount.text = assignedTasks.count { it.isCompleted }.toString()
    }

    private fun setupButtons() {
        binding.btnBack.setOnClickListener {
            findNavController().popBackStack()
        }

        binding.btnEditProfile.setOnClickListener {
            findNavController().navigate(R.id.action_profile_to_editProfile)
        }

        binding.btnChangePassword.setOnClickListener {
            findNavController().navigate(R.id.action_profile_to_changePassword)
        }

        binding.btnChangePicture.setOnClickListener {
            galleryLauncher.launch("image/*")
        }

        binding.btnLogout.setOnClickListener {
            session.logout()
            startActivity(Intent(requireContext(), AuthActivity::class.java).apply {
                flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
            })
        }
    }

    private fun handleImageSelection(uri: Uri) {
        try {
            val inputStream = requireContext().contentResolver.openInputStream(uri)
            val originalBitmap = BitmapFactory.decodeStream(inputStream)
            inputStream?.close()

            val compressedBitmap = compressBitmap(originalBitmap, 200 * 1024) // 200KB
            val base64String = bitmapToBase64(compressedBitmap)

            repo.updateProfilePicture(currentUser.id, base64String)

            // Refresh user and avatar
            currentUser = repo.findUserById(currentUser.id) ?: currentUser
            setupAvatar()

            Toast.makeText(requireContext(), "Profile picture updated", Toast.LENGTH_SHORT).show()
        } catch (e: Exception) {
            Toast.makeText(requireContext(), "Failed to update profile picture", Toast.LENGTH_SHORT).show()
        }
    }

    private fun compressBitmap(bitmap: Bitmap, maxSizeBytes: Int): Bitmap {
        var quality = 100
        var compressedBitmap = bitmap

        do {
            val outputStream = ByteArrayOutputStream()
            compressedBitmap.compress(Bitmap.CompressFormat.JPEG, quality, outputStream)
            val byteArray = outputStream.toByteArray()
            if (byteArray.size <= maxSizeBytes) break
            quality -= 5
            if (quality < 10) {
                // Resize if quality too low
                val scale = Math.sqrt((maxSizeBytes.toDouble() / byteArray.size.toDouble()))
                val newWidth = (bitmap.width * scale).toInt()
                val newHeight = (bitmap.height * scale).toInt()
                compressedBitmap = Bitmap.createScaledBitmap(bitmap, newWidth, newHeight, true)
                quality = 100
            }
        } while (quality > 10)

        return compressedBitmap
    }

    private fun bitmapToBase64(bitmap: Bitmap): String {
        val outputStream = ByteArrayOutputStream()
        bitmap.compress(Bitmap.CompressFormat.JPEG, 100, outputStream)
        val byteArray = outputStream.toByteArray()
        return Base64.encodeToString(byteArray, Base64.DEFAULT)
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}
